<?php require_once __DIR__ . '/includes/admin-header.php'; exigir_perfil(['administrador']);
if($_SERVER['REQUEST_METHOD']==='POST'){ validar_csrf(); if(isset($_POST['excluir'])){$pdo->prepare('DELETE FROM bancos_dados WHERE id=?')->execute([$_POST['id']]); registrar_log($pdo,'Bancos de dados','Excluiu cadastro ID '.$_POST['id']);}else{$pdo->prepare('INSERT INTO bancos_dados (nome_conexao,host,banco,usuario,senha,porta,charset,ativo,criado_em) VALUES (?,?,?,?,?,?,?,?,NOW())')->execute([$_POST['nome_conexao'],$_POST['host'],$_POST['banco'],$_POST['usuario'],$_POST['senha'],$_POST['porta'],$_POST['charset'],isset($_POST['ativo'])?1:0]); registrar_log($pdo,'Bancos de dados','Cadastrou conexão '.$_POST['nome_conexao']);}}
$rows=$pdo->query('SELECT * FROM bancos_dados ORDER BY id DESC')->fetchAll();
?>
<h1>Cadastro de bancos de dados</h1><p class="muted">Guarda conexões para integração. A conexão principal continua em <b>config/banco.php</b>.</p><div class="grid-2"><section class="panel"><h2>Nova conexão</h2><form method="post" class="form-grid"><input type="hidden" name="csrf_token" value="<?= csrf_token() ?>"><label>Nome<input name="nome_conexao" required></label><label>Host<input name="host" value="localhost" required></label><label>Banco<input name="banco" required></label><label>Usuário<input name="usuario" required></label><label>Senha<input type="password" name="senha"></label><label>Porta<input type="number" name="porta" value="3306"></label><label>Charset<input name="charset" value="utf8mb4"></label><label class="check"><input type="checkbox" name="ativo" checked> Ativo</label><button class="btn primary">Salvar conexão</button></form></section><section class="panel"><h2>Conexões</h2><div class="table-wrap"><table><thead><tr><th>Nome</th><th>Host</th><th>Banco</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><?= e($r['nome_conexao']) ?></td><td><?= e($r['host']) ?></td><td><?= e($r['banco']) ?></td><td><?= $r['ativo']?'Ativa':'Inativa' ?></td><td><form method="post"><input type="hidden" name="csrf_token" value="<?= csrf_token() ?>"><input type="hidden" name="id" value="<?= (int)$r['id'] ?>"><button name="excluir">Excluir</button></form></td></tr><?php endforeach; ?></tbody></table></div></section></div><?php require_once __DIR__ . '/includes/admin-footer.php'; ?>
